!function(){"use strict";document.querySelector("form").addEventListener("submit",(e=>{e.preventDefault();let t=document.getElementById("newsletter"),n=document.getElementById("email"),r=new FormData(t);fetch("/",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams(r).toString()}).then((()=>{alert("Form successfully submitted"),n.value=""})).catch((e=>alert(e)))}))}();